import java.util.Scanner;
import org.apache.commons.text.StringEscapeUtils;

public class SecureXSSExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String userInput = scanner.nextLine();

        // Escape user input to prevent XSS attacks
        String escapedUserInput = StringEscapeUtils.escapeHtml4(userInput);

        System.out.println("Welcome, " + escapedUserInput + "!");

        // Output sanitized user input
        System.out.println("<script>alert('XSS Attack!')</script> Hello, " + escapedUserInput + "!");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
